INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES
(gen_random_uuid(), 'et', 8, 1, NULL, 'Charles Spurgeon em Et 8:1', 'Segundo Charles Spurgeon, a coerência doutrinária aplicada à vida cristã ilumina o sentido deste texto. Ester 8 mostra que providência divina na história do povo de Deus sustenta a caminhada da fé, especialmente em arrependimento sincero. A doutrina aqui conduz à devoção e à perseverança. Aplicação: firme-se nas promessas divinas e pratique a verdade com humildade.', 'Charles Spurgeon', 'commentary', '#1D4ED8', NOW()),
(gen_random_uuid(), 'et', 9, 1, NULL, 'Jerônimo em Et 9:1', 'Jerônimo destaca a leitura cristológica e eclesial da passagem. Em Ester 9, o foco recai sobre providência divina na história do povo de Deus e chama a igreja para vida de oração. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Jerônimo', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'et', 10, 1, NULL, 'John Owen em Et 10:1', 'John Owen interpreta este versículo a partir de a piedade prática e a santificação do coração. Em Ester 10, Deus revela providência divina na história do povo de Deus de forma pastoral e transformadora, promovendo santidade prática. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'John Owen', 'commentary', '#2E8B57', NOW()),
(gen_random_uuid(), 'jo', 1, 1, NULL, 'Atanásio em Jó 1:1', 'Atanásio destaca a leitura cristológica e eclesial da passagem. Em Jó 1, o foco recai sobre adoração, sabedoria e temor do Senhor e chama a igreja para justiça com misericórdia. O texto orienta a fé para uma obediência concreta e perseverante. Aplicação: receba esta verdade com fé, arrependimento e esperança ativa.', 'Atanásio', 'commentary', '#8B4513', NOW()),
(gen_random_uuid(), 'jo', 2, 1, NULL, 'Thomas Watson em Jó 2:1', 'Thomas Watson interpreta este versículo a partir de a piedade prática e a santificação do coração. Em Jó 2, Deus revela adoração, sabedoria e temor do Senhor de forma pastoral e transformadora, promovendo perseverança na tribulação. A verdade bíblica forma caráter, culto e missão. Aplicação: responda com oração, disciplina espiritual e serviço cristão.', 'Thomas Watson', 'commentary', '#2E8B57', NOW()),
